import * as LogUtil from "@/common/LogUtil";
import * as User from "@/rest/User";

import AlertModal from '@/components/modal/AlertModal'

export default {
  components: {
    AlertModal
  },
  data: () => ({
    alertModalParams: { isOpened: false, title: '', message: ''},

    isPasswordView: false,
    
    LOGIN_ID: null,
    PASSWORD: null,
  }),
  methods: {
    showAlertModal(msg) {
      this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
    },
    doLogin() {
      // [LOCAL-MODE] 서버 미가동 상태에서 로컬 실행용 로그인 우회.
      // 원본 서버 인증 로직은 아래 주석 블록에 보존.
      if(this.LOGIN_ID == null) {
        this.showAlertModal('로그인 ID를 입력하지 않았습니다.');
        return;
      }
      if(this.PASSWORD == null) {
        this.showAlertModal('비밀번호를 입력하지 않았습니다.');
        return;
      }
      this.$store.commit('SET_LOGIN', true);
      this.$store.commit('SET_USER', {
        USER_ID: 'local',
        LOGIN_ID: this.LOGIN_ID,
        USER_NAME: 'Local User',
        ROLE: 'ADMIN',
      });
      this.$router.push('/dashboard');

      /* [LOCAL-MODE] 원본 서버 호출 로직 (서버 복구 후 복구할 것)
      User.login({
        LOGIN_ID: this.LOGIN_ID,
        PASSWORD: this.PASSWORD
      }).then(res => {
        if(res.data.RES_CODE>=0) {
          LogUtil.debug("doLogIn(): USER=", res.data.ITEM);
          this.$store.commit('SET_LOGIN', true);
          this.$store.commit('SET_USER', res.data.ITEM);
          this.$router.push('/dashboard');
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
      });
      */
    },
    passwordViewChange() {
        this.isPasswordView = !this.isPasswordView;
    },
  },
};